    private static final Set<String> ALLOWED_PROTOCOLS = new HashSet<>(Arrays.asList("http", "https"));

    // Blocked hostnames that could be used for SSRF attacks
    private static final Set<String> BLOCKED_HOSTNAMES = new HashSet<>(Arrays.asList(
        "localhost", "localhost.localdomain", "ip6-localhost", "ip6-loopback",
        "metadata.google.internal", "metadata", "kubernetes.default"
    ));

